import { diffArrays, applyPatch } from '../src/arrayDiff'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("diff no change", diffArrays([1,2,3],[1,2,3]).every(o=>o.op==="keep"), true)
await check("diff addition", diffArrays([1,2],[1,2,3]).some(o=>o.op==="add"&&o.value===3), true)
await check("diff removal", diffArrays([1,2,3],[1,3]).some(o=>o.op==="remove"&&o.value===2), true)
await check("applyPatch produces target", JSON.stringify(applyPatch([1,2,3],diffArrays([1,2,3],[1,4,3]))), "[1,4,3]")
await check("diff empty to", diffArrays([1,2],[]).every(o=>o.op==="remove"), true)
await check("diff empty from", diffArrays([],[1,2]).every(o=>o.op==="add"), true)
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
